mapper.select:
SELECT id, module, operation, method, params, ip, user_id, username,
       operation_time, status, error_msg
FROM bc_sports_sys_log


        AND module = #{query.module}


        AND username LIKE '%' || #{query.username} || '%'


        AND status = #{query.status}


        AND operation_time >= #{query.startTime}


        AND operation_time <= #{query.endTime}


ORDER BY operation_time DESC
